+/// Fold select(c2, (select c1, a, b), (select c1, b, a)) -> select(xor(c1, c2), b, a).
+/// Fold select(c2, (select c1, a, b), (select c1, b, a)) -> select(xor(c1, c2), b, a).
+static Instruction *foldSelectOfSelects(SelectInst &OuterSel,
+                                        InstCombiner::BuilderTy &Builder,
+                                        InstCombinerImpl &IC) {
+  Value *CondOuter = OuterSel.getCondition();
+  Value *TrueVal = OuterSel.getTrueValue();
+  Value *FalseVal = OuterSel.getFalseValue();
+  auto *Sel1 = dyn_cast<SelectInst>(TrueVal);
+  auto *Sel2 = dyn_cast<SelectInst>(FalseVal);
+  if (!Sel1 || !Sel2)
+    return nullptr;
+  // If the inner selects have extra uses, we can't fold.
+  if (!Sel1->hasOneUse() || !Sel2->hasOneUse())
+    return nullptr;
+  // Both selects must have same condition.
+  Value *CondInner = Sel1->getCondition();
+  if (CondInner != Sel2->getCondition())
+    return nullptr;
+  // True/False values must be swapped between the two selects.
+  bool Swapped = (Sel1->getTrueValue() == Sel2->getFalseValue() &&
+                  Sel1->getFalseValue() == Sel2->getTrueValue());
+  if (!Swapped) {
+    // Identical selects: OuterSel is selecting between same two values, can be
+    // simplified by earlier folds.
+    return nullptr;
+  }
+  // The condition types must match for xor.
+  if (CondInner->getType() != CondOuter->getType())
+    return nullptr;
+  Value *A = Sel1->getTrueValue();
+  Value *B = Sel1->getFalseValue();
+  // Now OuterSel is: CondOuter ? (CondInner ? A : B) : (CondInner ? B : A)
+  // Transform to: CondInner xor CondOuter ? B : A
+  Value *XorCond = Builder.CreateXor(CondInner, CondOuter);
+  Value *NewSel = Builder.CreateSelect(XorCond, B, A);
+  NewSel->takeName(&OuterSel);
+  return IC.replaceInstUsesWith(OuterSel, NewSel);
+}

 static bool isSelect01(const APInt &C1I, const APInt &C2I) {
   if (!C1I.isZero() && !C2I.isZero()) // One side must be zero.
@@ -3713,6 +3752,11 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     return Or;
   if (Instruction *Mul = foldSelectZeroOrMul(SI, *this))
