+  // Fold select(c2, (select c1, a, b), (select c1, b, a)) -> select(xor(c1, c2), b, a)
+  if (SelectInst *Sel1 = dyn_cast<SelectInst>(TrueVal))
+    if (SelectInst *Sel2 = dyn_cast<SelectInst>(FalseVal))
+      if (Instruction *R = foldSelectOfSelects(SI, Builder, *this))
+        return R;

